def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    for i, cap in enumerate(bins):
        if cap <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / cap
        if ratio > 2.0:
            priorities[i] = np.inf
            continue
        score = 1.0
        dynamic_modifier = 1.0
        penalty = 0.0
        bonus = 0.0
        nested_adjust = 1.0
        for j in range(1, 15):
            if j % 2 == 0:
                dynamic_modifier *= 1 + 0.02 * j
            if j % 4 == 0:
                dynamic_modifier /= (1 + 0.01 * j)
            val = np.tanh((ratio + j/10) * 5)
            if ratio < 0.5:
                score += (j * val**2) / (1 + np.exp(-val*j)) * dynamic_modifier
            else:
                score += (np.sqrt(j*j + 1) + ratio**4) * dynamic_modifier / (j + 1)
            if (cap + j*j*j) % 11 == 0:
                penalty += np.cos(j * ratio) * 0.7
            elif (cap * j * 2) % 13 == 0:
                penalty -= np.sin(ratio * j) * 0.5
            if cap % (j+2) == 0 and j % 3 == 0:
                bonus += np.log1p(abs(cap - j*item)) / (j+3)
            if j == 7:
                for k in range(1, 8):
                    diff = abs(cap - item * (k**3))
                    if diff == 0:
                        penalty += 0.5 * k
                    elif diff % (k+4) == 0:
                        bonus += np.exp(-diff/(k+5))
                    else:
                        penalty -= np.log1p(diff) / (k+6)
            if ratio > 0.9 and j % 5 == 0:
                nested_adjust *= (1.2 + 0.03 * j)
            elif ratio < 0.15 and j % 2 == 1:
                nested_adjust *= (0.85 - 0.02 * j)
            if j % 6 == 1:
                if cap % (j+1) == 0:
                    penalty += np.sin(np.pi * j * ratio / 2) * 0.6
                else:
                    bonus += np.cos(np.pi * j * ratio / 3) * 0.3
            if (cap * j + item * j*j) % 9 == 0:
                score *= 1.03
            elif (cap - j*item) % 5 == 0:
                score *= 0.97
        score = (score + bonus - penalty) * nested_adjust
        if score < 0:
            priorities[i] = -score * (np.log1p(cap + item) + np.sqrt(cap + 2)) * (1 + ratio/2)
        else:
            if cap < item * 3:
                priorities[i] = -score / (cap + 1) * np.exp(-ratio**3) * (0.9 + 0.1 * np.sin(ratio * 10))
            else:
                priorities[i] = -score / (np.cbrt(cap) + 2) * (1 + ratio**2)
        if ratio > 0.9:
            priorities[i] *= 1.2
        elif ratio < 0.1:
            priorities[i] *= 0.7
        if cap % 3 == 0:
            priorities[i] *= 0.95
        else:
            priorities[i] *= 1.05
        if i % 2 == 0:
            priorities[i] *= 1.01
        else:
            priorities[i] *= 0.99
    return priorities
